"""
This module represents the Checkers (Draughts) board.
"""

from enum import Enum, unique
import numpy as np

class Piece(Enum):
    EMPTY = 0
    RED = 1
    BLACK = 2
    RED_KING = 3
    BLACK_KING = 4

class Move:
    def __init__(self, from_pos, to_pos, capture=None):
        self.from_pos = from_pos
        self.to_pos = to_pos
        self.capture = capture

    def __str__(self):
        return f"{chr(ord('a') + self.from_pos[1])}{8 - self.from_pos[0]}-{chr(ord('a') + self.to_pos[1])}{8 - self.to_pos[0]}"

class Board:
    def __init__(self):
        self.board = np.zeros((8, 8), dtype=int)
        self.initialize_board()

    def initialize_board(self):
        for i in range(3):
            for j in range(i % 2, 8, 2):
                self.board[i][j] = Piece.RED.value
        for i in range(5, 8):
            for j in range((i + 1) % 2, 8, 2):
                self.board[i][j] = Piece.BLACK.value

    def is_valid_move(self, move, turn):
        piece = self.board[move.from_pos[0]][move.from_pos[1]]
        if (turn == Piece.RED and piece not in [Piece.RED, Piece.RED_KING]) or \
           (turn == Piece.BLACK and piece not in [Piece.BLACK, Piece.BLACK_KING]):
            return False
        dx = move.to_pos[0] - move.from_pos[0]
        dy = abs(move.to_pos[1] - move.from_pos[1])
        if dx != 1:
            return False
        if dy == 2 and not self.is_capture_move(move):
            return False
        if piece in [Piece.RED, Piece.BLACK]:
            return abs(dy) == 1
        elif piece in [Piece.RED_KING, Piece.BLACK_KING]:
            return abs(dy) == 1 or abs(dy) == 2

    def is_capture_move(self, move):
        return abs(move.to_pos[1] - move.from_pos[1]) == 2 and self.board[(move.from_pos[0] + move.to_pos[0]) // 2][(move.from_pos[1] + move.to_pos[1]) // 2] != Piece.EMPTY

    def make_move(self, move):
        from_x, from_y = move.from_pos
        to_x, to_y = move.to_pos
        self.board[to_x][to_y] = self.board[from_x][from_y]
        self.board[from_x][from_y] = Piece.EMPTY
        if move.capture:
            self.board[(move.from_pos[0] + move.to_pos[0]) // 2][(move.from_pos[1] + move.to_pos[1]) // 2] = Piece.EMPTY

    def get_valid_moves(self, turn):
        moves = []
        for i in range(8):
            for j in range(8):
                if self.board[i][j] in [turn.value, (turn.value + 3) % 4]:
                    moves.extend(self.get_piece_moves(i, j, turn))
        return moves

    def get_piece_moves(self, x, y, turn):
        piece = self.board[x][y]
        moves = []
        if piece == Piece.EMPTY:
            return moves
        for dx in range(-1, 2, 2):
            for dy in range(-1, 2, 2):
                move = Move((x, y), (x + dx, y + dy))
                if self.is_valid_move(move, turn):
                    moves.append(move)
        return moves

    def is_game_over(self):
        return len(self.get_valid_moves(Piece.RED)) == 0 or len(self.get_valid_moves(Piece.BLACK)) == 0
```

