from .board import Board
from .piece import Piece

class Game:
    def __init__(self):
        self.board = Board()
        self.current_player = 'r'

    def switch_player(self):
        self.current_player = 'b' if self.current_player == 'r' else 'r'

    def move_piece(self, from_pos, to_pos):
        x1, y1 = map(int, from_pos.split(','))
        x2, y2 = map(int, to_pos.split(','))

        piece = self.board.board[x1][y1]
        if piece and piece.color == self.current_player:
            if self.is_valid_move(piece, (x1, y1), (x2, y2)):
                self.board.board[x2][y2] = piece
                self.board.board[x1][y1] = None

                # Promote to king if reaching the end of the board
                if piece.color == 'r' and x2 == 0:
                    piece.promote_to_king()
                elif piece.color == 'b' and x2 == 7:
                    piece.promote_to_king()

                self.switch_player()

    def is_valid_move(self, piece, start, end):
        # Simple move validation (not capturing)
        dx = abs(end[0] - start[0])
        dy = abs(end[1] - start[1])

        if dx != 1 or dy != 1:
            return False

        if self.board.board[end[0]][end[1]]:
            return False

        return True

    def check_winner(self):
        # Check if all pieces of one color are captured
        red_count = sum(1 for row in self.board.board for piece in row if piece and piece.color == 'r')
        black_count = sum(1 for row in self.board.board for piece in row if piece and piece.color == 'b')

        if red_count == 0:
            return 'Black wins!'
        elif black_count == 0:
            return 'Red wins!'

        return None

    def play(self):
        print("Welcome to Checkers!")
        self.board.print_board()

        while True:
            move = input(f"Player {self.current_player}, enter your move (from-to): ")
            if move.lower() == 'exit':
                break

            from_pos, to_pos = move.split(' ')
            self.move_piece(from_pos, to_pos)

            self.board.print_board()
            winner = self.check_winner()
            if winner:
                print(winner)
                break
